export const contentService = {
  async getPopularContent() {
    // Mock data
    return [
      {
        id: 1,
        title: 'Berserk',
        type: 'Манга',
        author: 'Kentaro Miura',
        cover: 'https://placehold.co/400x600/ff6b6b/white?text=Berserk',
        rating: 4.9,
        chapters: 363,
        views: 1250000
      },
      {
        id: 2,
        title: 'Solo Leveling',
        type: 'Манхва',
        author: 'Chugong',
        cover: 'https://placehold.co/400x600/4ecdc4/white?text=Solo+Leveling',
        rating: 4.8,
        chapters: 179,
        views: 980000
      },
      {
        id: 3,
        title: 'Tower of God',
        type: 'Манхва',
        author: 'SIU',
        cover: 'https://placehold.co/400x600/45b7d1/white?text=Tower+of+God',
        rating: 4.7,
        chapters: 560,
        views: 850000
      },
      {
        id: 4,
        title: 'One Piece',
        type: 'Манга',
        author: 'Eiichiro Oda',
        cover: 'https://placehold.co/400x600/96ceb4/white?text=One+Piece',
        rating: 4.9,
        chapters: 1085,
        views: 1500000
      }
    ];
  },

  async getTopUsers() {
    return [
      { id: 1, username: 'DarkLord', level: 5, points: 12500, avatar: null },
      { id: 2, username: 'MangaMaster', level: 5, points: 9800, avatar: null },
      { id: 3, username: 'WeebQueen', level: 4, points: 7200, avatar: null },
      { id: 4, username: 'AnimeLover', level: 4, points: 6500, avatar: null },
      { id: 5, username: 'KawaiiChan', level: 3, points: 4200, avatar: null }
    ];
  },

  async uploadContent(contentData) {
    console.log('Uploading content:', contentData);
    // Mock upload
    return new Promise((resolve) => {
      setTimeout(() => {
        resolve({ success: true, id: Date.now() });
      }, 2000);
    });
  }
};
